class Solution:
    def vowelConsonantScore(self, s: str) -> int:
        vowels = set('aeiou')
        v = c = 0
        for ch in s:
            if 'a' <= ch <= 'z':
                if ch in vowels:
                    v += 1
                else:
                    c += 1
        return v // c if c > 0 else 0

solutions.javascript:
var vowelConsonantScore = function(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    let v = 0, c = 0;
    for (const ch of s) {
        if (ch >= 'a' && ch <= 'z') {
            if (vowels.has(ch)) v++;
            else c++;
        }
    }
    return c > 0 ? Math.floor(v / c) : 0;
};
